1	{
2	  description = "LLM2FPGA";
3	
4	  inputs = {
5	    nixpkgs.url = "github:NixOS/nixpkgs/nixos-24.05";
6	    nixpkgs-llvm21.url =
7	      "github:NixOS/nixpkgs/346dd96ad74dc4457a9db9de4f4f57dab2e5731d";
8	    flake-utils.url = "github:numtide/flake-utils";
9	    # Clone with submodules
10	    yosys.url = "git+https://github.com/YosysHQ/yosys?submodules=1";
11	    yosys-slang = {
12	      url = "git+https://github.com/povik/yosys-slang?submodules=1";
13	      flake = false;
14	    };
15	    circt-src = {
16	      type = "github";
17	      owner = "RCoeurjoly";
18	      repo = "circt";
19	      ref = "task3";
20	      flake = false;
21	    };
22	    circt-nix = {
23	      url = "git+https://github.com/dtzSiFive/circt-nix?ref=main";
24	      inputs."circt-src".follows = "circt-src";
25	      inputs."llvm-submodule-src" = {
26	        type = "github";
27	        owner = "llvm";
28	        repo = "llvm-project";
29	        rev = "972cd847efb20661ea7ee8982dd19730aa040c75";
30	        flake = false;
31	      };
32	    };
33	    nix-eda.url = "github:fossi-foundation/nix-eda";
34	    openXC7.url = "github:RCoeurjoly/toolchain-nix";
35	    nextpnrXilinxFork = {
36	      url =
37	        "git+https://github.com/RCoeurjoly/nextpnr-xilinx?ref=stable-backports&submodules=1";
38	      flake = false;
39	    };
40	    ypcbHack = {
41	      url = "github:RCoeurjoly/ypcb_00338_1p1_hack";
42	      flake = false;
43	    };
44	  };
45	
46	  outputs = inputs@{ nixpkgs, nixpkgs-llvm21, flake-utils, yosys, circt-nix
47	    , nix-eda, openXC7, nextpnrXilinxFork, ypcbHack, ... }:
48	    flake-utils.lib.eachDefaultSystem (system:
49	      let
50	        pkgs = import nixpkgs { inherit system; };
51	        pkgsLlvm21 = import nixpkgs-llvm21 { inherit system; };
52	        circtPkgs = circt-nix.packages.${system};
53	        circtBase =
54	          (circtPkgs.circt.override { enableSlang = false; }).overrideAttrs
55	          (old: { patches = old.patches or [ ]; });
56	        # Keep reviewer builds on a pinned upstream CIRCT plus the checked-in
57	        # Task 3 patch stack. Local fast iteration should use local binaries via
58	        # scripts/dev rather than a flake input override.
59	        circt = circtBase;
60	        yosysPkg = nix-eda.packages.${system}.yosysFull.overrideAttrs (_: {
61	          src = yosys.outPath;
62	          version = "unstable-${builtins.substring 0 8 yosys.sourceInfo.rev}";
63	        });
64	        yosysPkgWithPythonEnv = if yosysPkg ? python3-env then
65	          yosysPkg
66	        else
67	          (yosysPkg // { python3-env = pkgs.python311; });
68	        yosysSlang = pkgs.clangStdenv.mkDerivation {
69	          pname = "yosys-slang";
70	          version = "flake-input";
71	          src = inputs."yosys-slang";
72	          dylibs = [ "slang" ];
73	          cmakeFlags = [
74	            "-DYOSYS_CONFIG=${yosysPkgWithPythonEnv}/bin/yosys-config"
75	            "-DFMT_INSTALL:BOOL=OFF"
76	          ];
77	          nativeBuildInputs = [ pkgs.cmake pkgs.jq ];
78	          buildInputs = [
79	            yosysPkgWithPythonEnv
80	            yosysPkgWithPythonEnv.python3-env
81	            pkgs.fmt
82	          ];
83	          patchPhase = ''
84	            runHook prePatch
85	            sed -i \
86	              -e '/git_rev_parse(YOSYS_SLANG_REVISION/c\set(YOSYS_SLANG_REVISION flake-input)' \
87	              -e '/git_rev_parse(SLANG_REVISION/c\set(SLANG_REVISION flake-input-submodule)' \
88	              src/CMakeLists.txt
89	            runHook postPatch
90	          '';
91	          doCheck = true;
92	          cmakeBuildType = "Debug";
93	          installPhase = ''
94	            runHook preInstall
95	            mkdir -p $out/share/yosys/plugins
96	            cp ../build/slang.so $out/share/yosys/plugins/
97	            runHook postInstall
98	          '';
99	          meta = {
100	            description = "SystemVerilog frontend for Yosys";
101	            license = [ pkgs.lib.licenses.mit ];
102	            homepage = "https://github.com/povik/yosys-slang";
103	            platforms = pkgs.lib.platforms.all;
104	          };
105	        };
106	        llvmPackages = pkgsLlvm21.llvmPackages_21;
107	        # Keep LLVM for torch-mlir separate and pinned to torch-mlir's
108	        # submodule revision so source edits in torch-mlir do not rebuild LLVM.
109	        torchMlirLlvmPackages = (pkgsLlvm21.llvmPackages_git.override {
110	          llvmVersions = {
111	            "22.0.0-git" = {
112	              gitRelease = {
113	                rev = "3ca2a5fc0b84762f0e7d8a0e613fd69f7e344219";
114	                rev-version = "23.0.0-unstable-2026-01-20";
115	                sha256 = "sha256-jjdb2PtKnjYo9RIGJ82YtKmZinqEOlmm7R64SeJqTac=";
116	              };
117	            };
118	          };
119	        }).overrideScope (final: prev: {
120	          # This commit reports LLVM 23 in source headers, while the package set
121	          # key stays on llvmPackages_git. Skip nixpkgs' strict version triplet
122	          # guard for this custom pin.
123	          libllvm = (prev.libllvm.override {
124	            # Ensure llvm builds against the matching tblgen from this pinned
125	            # package set, not the default llvmPackages_git bootstrap set.
126	            buildLlvmPackages = final;
127	          }).overrideAttrs (old: {
128	            postConfigure = "";
129	            doCheck = false;
130	            cmakeFlags = (old.cmakeFlags or [ ]) ++ [
131	              (pkgsLlvm21.lib.cmakeBool "LLVM_BUILD_TESTS" false)
132	              (pkgsLlvm21.lib.cmakeBool "LLVM_INCLUDE_TESTS" false)
133	            ];
134	          });
135	        });
136	        inherit (llvmPackages) mlir;
137	        python = pkgsLlvm21.python311;
138	        pythonWithTorch = python.withPackages (ps: [ ps.torch ps.packaging ]);
139	        pythonWithTinyStories =
140	          python.withPackages (ps: [ ps.torch ps.packaging ps.transformers ]);
141	        nanobindBootstrap =
142	          pkgsLlvm21.callPackage ./nix/nanobind-bootstrap.nix {
143	            inherit python;
144	          };
145	        mlirForTorchMlir = (torchMlirLlvmPackages.mlir.override {
146	          devExtraCmakeFlags =
147	            [ (pkgsLlvm21.lib.cmakeBool "MLIR_ENABLE_BINDINGS_PYTHON" true) ];
148	        }).overrideAttrs (old: {
149	          doCheck = false;
150	          nativeBuildInputs = old.nativeBuildInputs ++ [ python ];
151	          preConfigure = (old.preConfigure or "") + ''
152	            export PYTHONPATH="${python.pkgs.pybind11}/${python.sitePackages}:${nanobindBootstrap}/${python.sitePackages}:''${PYTHONPATH:-}"
153	          '';
154	          cmakeFlags = (old.cmakeFlags or [ ]) ++ [
155	            (pkgsLlvm21.lib.cmakeBool "LLVM_BUILD_TESTS" false)
156	            (pkgsLlvm21.lib.cmakeFeature "Python3_EXECUTABLE"
157	              "${python}/bin/python3")
158	            (pkgsLlvm21.lib.cmakeFeature "Python_EXECUTABLE"
159	              "${python}/bin/python3")
160	            (pkgsLlvm21.lib.cmakeFeature "pybind11_DIR"
161	              "${python.pkgs.pybind11}/${python.sitePackages}/pybind11/share/cmake/pybind11")
162	            (pkgsLlvm21.lib.cmakeFeature "nanobind_DIR"
163	              "${nanobindBootstrap}/${python.sitePackages}/nanobind/cmake")
164	          ];
165	        });
166	        openXC7Packages = openXC7.packages.${system};
167	        openXC7Fasm = openXC7Packages.fasm;
168	        openXC7Nextpnr = openXC7Packages.nextpnr-xilinx.overrideAttrs
169	          (_: { src = nextpnrXilinxFork; });
170	        openXC7Chipdb = openXC7Packages.nextpnr-xilinx-chipdb.kintex7.override {
171	          chipdbFootprints = [ "xc7k480tffg1156" ];
172	          "nextpnr-xilinx" = openXC7Nextpnr;
173	        };
174	        openXC7Prjxray = openXC7Packages.prjxray;
175	        prjxrayPythonDeps = pkgs.python312.withPackages (ps: [
176	          ps.pyyaml
177	          ps.simplejson
178	          ps.intervaltree
179	          ps.pyjson5
180	          ps.progressbar2
181	        ]);
182	        fpgaPartFamily = "kintex7";
183	        fpgaPartName = "xc7k480tffg1156-1";
184	        fpgaPrjxrayDb = "${openXC7Nextpnr}/share/nextpnr/external/prjxray-db";
185	        fpgaPrjxrayFamilyDb = "${fpgaPrjxrayDb}/${fpgaPartFamily}";
186	        fpgaPartFile = "${fpgaPrjxrayFamilyDb}/${fpgaPartName}/part.yaml";
187	        fpgaChipdb = "${openXC7Chipdb}/xc7k480tffg1156.bin";
188	        prjxrayPythonPath =
189	          "${openXC7Fasm}/lib/python3.12/site-packages:${prjxrayPythonDeps}/${pkgs.python312.sitePackages}:${openXC7Prjxray}/usr/share/python3";
190	        torchMlir = pkgsLlvm21.callPackage ./torch-mlir.nix {
191	          inherit python;
192	          nanobind = nanobindBootstrap;
193	          inherit (torchMlirLlvmPackages) tblgen;
194	          mlir = mlirForTorchMlir;
195	          inherit (torchMlirLlvmPackages) llvm;
196	        };
197	
198	        pipelineScripts = ./scripts/pipeline;
199	        fpPrimsSv = ./rtl/fp/circt_fp_primitives.sv;
200	        tinyStories1m = let
201	          modelId = "roneneldan/TinyStories-1M";
202	          revision = "77f1b168e219585646439073245fe87e56b3023e";
203	          fetch = file: hash:
204	            pkgs.fetchurl {
205	              url =
206	                "https://huggingface.co/${modelId}/resolve/${revision}/${file}";
207	              inherit hash;
208	            };
209	          snapshot = pkgs.linkFarm "tinystories-1m-hf-snapshot" [
210	            {
211	              name = "config.json";
212	              path = fetch "config.json"
213	                "sha256-/3TDDV67WrHaDy6kea33GXxQS0K1UiqFjDNKuR7UlYw=";
214	            }
215	            {
216	              name = "pytorch_model.bin";
217	              path = fetch "pytorch_model.bin"
218	                "sha256-B/lgnqiCuBY/87I9QOK4LLcV1AljG+sVyEsWTzh32uc=";
219	            }
220	          ];
221	        in {
222	          inherit snapshot;
223	          sourceDir = ./TinyStories;
224	          adapterPy = ./TinyStories/model_adapter.py;
225	        };
226	
227	        pipelineLib = import ./nix/pipeline.nix {
228	          inherit pkgs mlir circt yosysPkg yosysSlang torchMlir python;
229	          inherit pipelineScripts;
230	        };
231	
232	        modelRegistry = import ./nix/models.nix {
233	          inherit (pipelineLib) registerModel;
234	          inherit pythonWithTorch pythonWithTinyStories torchMlir python;
235	          inherit tinyStories1m;
236	          inherit fpPrimsSv;
237	          compilePyTorch = ./scripts/compile-pytorch.py;
238	          matmulPy = ./src/matmul.py;
239	          matmulAdapterPy = ./src/matmul_adapter.py;
240	          matmulSrcDir = ./src;
241	          simDir = ./sim;
242	        };
243	
244	        matmulSv = modelRegistry.matmul.pipeline.sv;
245	        tinyStories1mBaselineFloatIl =
246	          modelRegistry."tiny-stories-1m-baseline-float".pipeline.il;
247	        tinyStoriesSelftestTop = ./rtl/tiny_stories_selftest_top.sv;
248	        # https://docs.amd.com/v/u/en-US/7-series-product-selection-guide, search XC7K480T
249	        fpgaCapacities = {
250	          slices = 74650;
251	          clb_luts = 298600;
252	          clb_ffs = 597200;
253	          dsp = 1920;
254	          bram36 = 955;
255	          bram_kb = 34380;
256	        };
257	
258	        boardXdc = "${ypcbHack}/constraints/ypcb003381p1.xdc";
259	
260	        mkYosysRtlil = { name, quiet ? false, memoryLimitKb ? null, script }:
261	          pkgs.runCommand "${name}.il" { } ''
262	            cat > run.ys <<EOF
263	            ${script}
264	            EOF
265	            ${pkgs.lib.optionalString (memoryLimitKb != null) ''
266	              ulimit -v ${toString memoryLimitKb}
267	            ''}
268	            ${yosysPkg}/bin/yosys ${
269	              pkgs.lib.optionalString quiet "-q"
270	            } -m ${yosysSlang}/share/yosys/plugins/slang.so -s run.ys
271	
272	            if [ ! -e "$out" ]; then
273	              echo "mkYosysRtlil expected output path was not created: $out" >&2
274	              echo "--- run.ys ---" >&2
275	              cat run.ys >&2
276	              exit 1
277	            fi
278	          '';
279	
280	        mkSynthStageIl = { name, stageId, stageLabel, inputIl, topName
281	          , topSv ? null, quiet ? false, memoryLimitKb ? null, preCommands ? [ ]
282	          , commands }:
283	          pkgs.runCommand "${name}-${stageId}.il" { } ''
284	            cat > run.ys <<EOF
285	            ${builtins.concatStringsSep "\n" ([ "read_rtlil ${inputIl}" ]
286	              ++ pkgs.lib.optional (topSv != null) "read_slang ${topSv}"
287	              ++ [ "hierarchy -top ${topName} -check" ] ++ preCommands
288	              ++ commands ++ [ "write_rtlil $out" ])}
289	            EOF
290	
291	            ${pkgs.lib.optionalString (memoryLimitKb != null) ''
292	              ulimit -v ${toString memoryLimitKb}
293	            ''}
294	
295	            echo "[mkSynthJson:${name}] ${stageLabel}" >&2
296	            ${yosysPkg}/bin/yosys ${pkgs.lib.optionalString quiet "-q"} ${
297	              pkgs.lib.optionalString (topSv != null)
298	              "-m ${yosysSlang}/share/yosys/plugins/slang.so"
299	            } -s run.ys
300	
301	            if [ ! -e "$out" ]; then
302	              echo "mkSynthJson ${stageId} expected output path was not created: $out" >&2
303	              echo "--- run.ys ---" >&2
304	              cat run.ys >&2
305	              exit 1
306	            fi
307	          '';
308	
309	        mkSynthStageMemoryMapIl = { name, stageId, stageLabel, inputIl, topName
310	          , quiet ? false, memoryLimitKb ? null }:
311	          pkgs.runCommand "${name}-${stageId}.il" { } ''
312	            ${pkgs.gawk}/bin/awk '
313	              /^module / { mod = $2 }
314	              /^[[:space:]]*cell \$mem/ { mods[mod] = 1 }
315	              END {
316	                for (mod in mods)
317	                  print mod
318	              }
319	            ' ${inputIl} | sort > stage-modules.txt
320	
321	            cat > run.ys <<EOF
322	            read_rtlil ${inputIl}
323	            hierarchy -top ${topName} -check
324	            EOF
325	
326	            while IFS= read -r moduleName; do
327	              printf '%s\n' \
328	                "cd $moduleName" \
329	                'memory_map' \
330	                'cd ..' \
331	                >> run.ys
332	            done < stage-modules.txt
333	
334	            printf '%s\n' "write_rtlil $out" >> run.ys
335	
336	            ${pkgs.lib.optionalString (memoryLimitKb != null) ''
337	              ulimit -v ${toString memoryLimitKb}
338	            ''}
339	
340	            echo "[mkSynthJson:${name}] ${stageLabel}" >&2
341	            ${yosysPkg}/bin/yosys ${
342	              pkgs.lib.optionalString quiet "-q"
343	            } -s run.ys
344	
345	            if [ ! -e "$out" ]; then
346	              echo "mkSynthJson ${stageId} expected output path was not created: $out" >&2
347	              echo "--- run.ys ---" >&2
348	              cat run.ys >&2
349	              exit 1
350	            fi
351	          '';
352	
353	        mkSynthStageJson = { name, stageId, stageLabel, inputIl, quiet ? false
354	          , memoryLimitKb ? null }:
355	          pkgs.runCommand "${name}.json" { } ''
356	            ${pkgs.python311}/bin/python3 ${
357	              ./scripts/pipeline/filter_rtlil_modules.py
358	            } \
359	              --input ${inputIl} \
360	              --output stage8-stripped.il \
361	              --drop-escaped-uppercase-modules
362	
363	            cat > run.ys <<EOF
364	            read_rtlil stage8-stripped.il
365	            proc
366	            write_json $out
367	            EOF
368	
369	            ${pkgs.lib.optionalString (memoryLimitKb != null) ''
370	              ulimit -v ${toString memoryLimitKb}
371	            ''}
372	
373	            echo "[mkSynthJson:${name}] ${stageLabel}" >&2
374	            ${yosysPkg}/bin/yosys ${
375	              pkgs.lib.optionalString quiet "-q"
376	            } -s run.ys
377	
378	            if [ ! -e "$out" ]; then
379	              echo "mkSynthJson ${stageId} expected output path was not created: $out" >&2
380	              echo "--- run.ys ---" >&2
381	              cat run.ys >&2
382	              exit 1
383	            fi
384	          '';
385	
386	        mkSynthJsonStages = { name, modelIl, topName, topSv ? null
387	          , quiet ? false, memoryLimitKb ? null }: rec {
388	            stage1 = mkSynthStageIl {
389	              inherit name topName topSv quiet memoryLimitKb;
390	              stageId = "stage1";
391	              stageLabel = "stage1 synth_xilinx begin:prepare";
392	              inputIl = modelIl;
393	              preCommands = [ "proc" ];
394	              commands = [
395	                "synth_xilinx -family xc7 -top ${topName} -noiopad -run begin:prepare"
396	              ];
397	            };
398	
399	            stage2 = mkSynthStageIl {
400	              inherit name topName quiet memoryLimitKb;
401	              stageId = "stage2";
402	              stageLabel = "stage2 synth_xilinx coarse:map_memory";
403	              inputIl = stage1;
404	              commands = [
405	                "synth_xilinx -family xc7 -top ${topName} -noiopad -run coarse:map_memory"
406	              ];
407	            };
408	
409	            stage3 = mkSynthStageIl {
410	              inherit name topName quiet memoryLimitKb;
411	              stageId = "stage3";
412	              stageLabel = "stage3 opt -fast -full";
413	              inputIl = stage2;
414	              commands = [ "opt -fast -full" ];
415	            };
416	
417	            stage4 = mkSynthStageMemoryMapIl {
418	              inherit name topName quiet memoryLimitKb;
419	              stageId = "stage4";
420	              stageLabel = "stage4 targeted memory_map";
421	              inputIl = stage3;
422	            };
423	
424	            stage5 = mkSynthStageIl {
425	              inherit name topName quiet memoryLimitKb;
426	              stageId = "stage5";
427	              stageLabel = "stage5 synth_xilinx fine:fine";
428	              inputIl = stage4;
429	              commands = [
430	                "synth_xilinx -family xc7 -top ${topName} -noiopad -run fine:fine"
431	              ];
432	            };
433	
434	            stage6 = mkSynthStageIl {
435	              inherit name topName quiet memoryLimitKb;
436	              stageId = "stage6";
437	              stageLabel = "stage6 synth_xilinx map_cells:map_cells";
438	              inputIl = stage5;
439	              commands = [
440	                "synth_xilinx -family xc7 -top ${topName} -noiopad -run map_cells:map_cells"
441	              ];
442	            };
443	
444	            stage7 = mkSynthStageIl {
445	              inherit name topName quiet memoryLimitKb;
446	              stageId = "stage7";
447	              stageLabel = "stage7 synth_xilinx map_ffs:map_ffs";
448	              inputIl = stage6;
449	              commands = [
450	                "synth_xilinx -family xc7 -top ${topName} -noiopad -run map_ffs:map_ffs"
451	              ];
452	            };
453	
454	            stage8 = mkSynthStageIl {
455	              inherit name topName quiet memoryLimitKb;
456	              stageId = "stage8";
457	              stageLabel = "stage8 final synth/write";
458	              inputIl = stage7;
459	              commands = [
460	                "synth_xilinx -family xc7 -top ${topName} -noiopad -run map_luts:check"
461	              ];
462	            };
463	
464	            stage9 = mkSynthStageJson {
465	              inherit name quiet memoryLimitKb;
466	              stageId = "stage9";
467	              stageLabel = "stage9 write_json";
468	              inputIl = stage8;
469	            };
470	
471	            json = stage9;
472	          };
473	
474	        appendYosysCommands = commands: ''
475	          cat >> run.ys <<EOF
476	          ${pkgs.lib.concatStringsSep "\n" commands}
477	          EOF
478	        '';
479	
480	        appendReadSlangFromFilelist = { svFilelist, topSv }: ''
481	          {
482	            printf 'read_slang --threads 1 --no-proc'
483	            while IFS= read -r line; do
484	              if [ -z "''${line//[[:space:]]/}" ]; then
485	                continue
486	              fi
487	              if [ "''${line#\#}" != "$line" ]; then
488	                continue
489	              fi
490	              printf ' %q' "$line"
491	            done < ${svFilelist}
492	            printf ' %q' ${topSv}
493	            printf '\n'
494	          } >> run.ys
495	        '';
496	
497	        mkSynthJson =
498	          { name, modelIl ? null, svFilelist ? null, topName, topSv }:
499	          let
500	            useModelIl = modelIl != null;
501	            useSvFilelist = svFilelist != null;
502	            inputScript = if useModelIl then
503	              appendYosysCommands
504	              ([ "read_rtlil ${modelIl}" ] ++ [ "read_slang ${topSv}" ])
505	            else
506	              appendReadSlangFromFilelist {
507	                inherit svFilelist;
508	                inherit topSv;
509	              };
510	          in assert pkgs.lib.assertMsg (useModelIl != useSvFilelist)
511	            "mkSynthJson requires exactly one of `modelIl` or `svFilelist`";
512	          pkgs.runCommand "${name}.json" { } ''
513	            ${inputScript}
514	            ${appendYosysCommands [
515	              "hierarchy -top ${topName} -check"
516	              "proc"
517	              "synth_xilinx -family xc7 -top ${topName} -noiopad -json $out"
518	            ]}
519	
520	            echo "[mkSynthJson:${name}] stage8 final synth/write" >&2
521	            ${yosysPkg}/bin/yosys -m ${yosysSlang}/share/yosys/plugins/slang.so -s run.ys
522	
523	            if [ ! -e "$out" ]; then
524	              echo "mkSynthJson expected output path was not created: $out" >&2
525	              echo "--- run.ys ---" >&2
526	              cat run.ys >&2
527	              exit 1
528	            fi
529	          '';
530	
531	        mkMappedJsonUtilizationReport =
532	          { name, capacities, topName, designJson }:
533	          pkgs.runCommand "${name}-utilization" { } ''
534	            mkdir -p "$out"
535	            ${pkgs.python311}/bin/python3 ${
536	              ./scripts/pipeline/write_utilization_report.py
537	            } \
538	              --design-json ${designJson} \
539	              --top ${topName} \
540	              --summary-json "$out/summary.json" \
541	              --summary-txt "$out/summary.txt" \
542	              --stat-json "$out/stat.json" \
543	              --capacity-slices ${toString capacities.slices} \
544	              --capacity-clb-luts ${toString capacities.clb_luts} \
545	              --capacity-clb-ffs ${toString capacities.clb_ffs} \
546	              --capacity-dsp ${toString capacities.dsp} \
547	              --capacity-bram36 ${toString capacities.bram36} \
548	              --capacity-bram-kb ${toString capacities.bram_kb}
549	          '';
550	
551	        mkExternalizedMemoryPlan =
552	          { name, modelIl, minModuleBits ? (128 * 1024) }:
553	          pkgs.runCommand "${name}-external-memory-plan" { } ''
554	            ${pkgs.python311}/bin/python3 ${
555	              ./scripts/pipeline/externalize_large_memories.py
556	            } \
557	              --input ${modelIl} \
558	              --output-script externalize.ys \
559	              --output-report report.json \
560	              --min-module-bits ${toString minModuleBits}
561	            mkdir -p "$out"
562	            cp externalize.ys "$out/externalize.ys"
563	            cp report.json "$out/report.json"
564	          '';
565	
566	        mkTinyStoriesSelftestBundle = { name, topName, modelIl, capacities
567	          , externalMemoryMinModuleBits ? (128 * 1024) }:
568	          let
569	            top = tinyStoriesSelftestTop;
570	            modelOptIl = mkYosysRtlil {
571	              name = "${name}-model-opt";
572	              script = ''
573	                read_rtlil ${modelIl}
574	                hierarchy -top main -check
575	                proc
576	                opt_expr
577	                opt_clean
578	                clean
579	                write_rtlil $out
580	              '';
581	            };
582	            externalMemoryPlan = mkExternalizedMemoryPlan {
583	              inherit name;
584	              modelIl = modelOptIl;
585	              minModuleBits = externalMemoryMinModuleBits;
586	            };
587	            modelShellIl = mkYosysRtlil {
588	              name = "${name}-model-shell";
589	              script = ''
590	                read_rtlil ${modelOptIl}
591	                script ${externalMemoryPlan}/externalize.ys
592	                hierarchy -top main -check
593	                write_rtlil $out
594	              '';
595	            };
596	            stages = mkSynthJsonStages {
597	              inherit name topName;
598	              modelIl = modelShellIl;
599	              topSv = top;
600	              quiet = true;
601	            };
602	            utilizationReport = mkMappedJsonUtilizationReport {
603	              inherit name capacities topName;
604	              designJson = stages.json;
605	            };
606	          in { inherit stages utilizationReport; };
607	
608	        docsMdApp = pkgs.writeShellApplication {
609	          name = "docs-md";
610	          runtimeInputs = [ pkgs.pandoc pkgs.coreutils ];
611	          text = ''
612	          set -euo pipefail
613	
614	          repo="$(pwd -P)"
615	          if [ "$#" -gt 0 ]; then
616	            repo="$1"
617	          fi
618	          repo="$(cd "$repo" && pwd -P)"
619	
620	          while IFS= read -r src; do
621	            [ -f "$src" ] || continue
622	            dst="''${src%.org}.md"
623	            pandoc "$src" -f org -t gfm -o "$dst"
624	          done < <(printf '%s\n' "$repo/README.org" "$repo"/deliverables/*.org "$repo"/docs/*.org)
625	          echo "Generated markdown docs in: $repo"
626	          '';
627	        };
628	
629	        mkXdc = { name, includeBoardXdc ? true, extraConstraints ? [ ] }:
630	          let
631	            constraintFiles = (if includeBoardXdc then [ boardXdc ] else [ ])
632	              ++ extraConstraints;
633	          in pkgs.runCommand "${name}.xdc" { inherit constraintFiles; } ''
634	            cat $constraintFiles > "$out"
635	          '';
636	
637	        mkFasm = { name, xdc, json }:
638	          pkgs.runCommand "${name}.fasm" { } ''
639	            if [ ! -f "${fpgaChipdb}" ]; then
640	              echo "chipdb file missing: ${fpgaChipdb}" >&2
641	              exit 1
642	            fi
643	
644	            ${openXC7Nextpnr}/bin/nextpnr-xilinx \
645	              --chipdb "${fpgaChipdb}" \
646	              --xdc ${xdc} \
647	              --json ${json} \
648	              --fasm "$out"
649	          '';
650	
651	        mkBitstream = { name, fasm, framesBase }:
652	          pkgs.runCommand "${name}.bit" {
653	            nativeBuildInputs =
654	              [ openXC7Fasm openXC7Prjxray prjxrayPythonDeps ];
655	          } ''
656	            set -euo pipefail
657	            export PYTHONPATH="${prjxrayPythonPath}''${PYTHONPATH:+:$PYTHONPATH}"
658	            export PRJXRAY_PYTHON_DIR="${openXC7Prjxray}/usr/share/python3"
659	            export PRJXRAY_DB_DIR="${fpgaPrjxrayFamilyDb}"
660	            tmpdir="$(mktemp -d)"
661	            frames="$tmpdir/${framesBase}.frm"
662	            fasm2frames \
663	              --db-root "${fpgaPrjxrayFamilyDb}" \
664	              --part ${fpgaPartName} \
665	              ${fasm} "$frames"
666	            xc7frames2bit \
667	              --part_file "${fpgaPartFile}" \
668	              --frm_file "$frames" \
669	              --output_file "$out"
670	          '';
671	
672	        tinyStories1mBaselineFloatSelftestAllMemory =
673	          mkTinyStoriesSelftestBundle {
674	            name = "tiny-stories-1m-baseline-float-selftest-all-memory";
675	            topName = "tiny_stories_selftest_top";
676	            modelIl = tinyStories1mBaselineFloatIl;
677	            capacities = fpgaCapacities;
678	          };
679	
680	        matmulSelftestTop = ./fpga/rtl/matmul_selftest_top.sv;
681	        matmulSelftestJson = mkSynthJson {
682	          name = "matmul-selftest";
683	          svFilelist = "${matmulSv}/sources.f";
684	          topName = "matmul_selftest_top";
685	          topSv = matmulSelftestTop;
686	        };
687	        matmulSelftestXdc = mkXdc {
688	          name = "matmul-selftest";
689	          includeBoardXdc = false;
690	          extraConstraints = [ ./fpga/constraints/matmul_selftest.xdc ];
691	        };
692	        matmulSelftestFasm = mkFasm {
693	          name = "matmul-selftest";
694	          xdc = matmulSelftestXdc;
695	          json = matmulSelftestJson;
696	        };
697	        matmulSelftestBitstream = mkBitstream {
698	          name = "matmul-selftest";
699	          fasm = matmulSelftestFasm;
700	          framesBase = "matmul-selftest";
701	        };
702	
703	        tbDataSv = pkgs.runCommand "tb-data-sv" { } ''
704	          mkdir -p "$out"
705	          MATMUL_PY=${./src/matmul.py} \
706	          ${pythonWithTorch}/bin/python ${
707	            ./sim
708	          }/gen_tb_data.py > "$out/tb_data.sv"
709	        '';
710	
711	        simMain = pkgs.runCommand "sim-main" {
712	          buildInputs = [ pkgs.verilator pkgs.gcc pkgs.gnumake ];
713	        } ''
714	          set -euo pipefail
715	          mkdir -p "$out/obj_dir"
716	          verilator --binary --timing --language 1800-2017 -Wno-fatal \
717	            -I${tbDataSv} \
718	            -top tb -Mdir "$out/obj_dir" -o sim_main \
719	            -f ${matmulSv}/sources.f ${./sim/tb_main.sv}
720	        '';
721	
722	        matmulSvSim = pkgs.runCommand "matmul-sv-sim.json" {
723	          buildInputs = [ pkgs.gawk pkgs.gnugrep ];
724	        } ''
725	                    set -euo pipefail
726	                    ${simMain}/obj_dir/sim_main 2>&1 | tee sim.log
727	                    pass_line="$(${pkgs.gnugrep}/bin/grep -Eo 'PASS: expected [0-9]+ got [0-9]+' sim.log | tail -n1 || true)"
728	                    if [ -z "$pass_line" ]; then
729	                      echo "SV simulation did not produce a PASS line" >&2
730	                      exit 1
731	                    fi
732	                    expected="$(${pkgs.gawk}/bin/awk '{print $3}' <<<"$pass_line")"
733	                    got="$(${pkgs.gawk}/bin/awk '{print $5}' <<<"$pass_line")"
734	                    cat > "$out" <<EOF
735	          {
736	            "status": "PASS",
737	            "expected": $expected,
738	            "got": $got
739	          }
740	          EOF
741	        '';
742	
743	        matmulSvWave = pkgs.runCommand "matmul-wave.vcd" {
744	          buildInputs = [ pkgs.verilator pkgs.gcc pkgs.gnumake ];
745	        } ''
746	          set -euo pipefail
747	          mkdir -p obj_dir
748	          verilator --binary --trace -DENABLE_WAVES -DENABLE_WAVES_VCD --timing --language 1800-2017 -Wno-fatal \
749	            -I${tbDataSv} \
750	            -top tb -Mdir obj_dir -o sim_main \
751	            -f ${matmulSv}/sources.f ${./sim/tb_main.sv}
752	          ./obj_dir/sim_main
753	          if [ ! -f wave.vcd ]; then
754	            echo "wave.vcd was not produced by simulation" >&2
755	            exit 1
756	          fi
757	          cp wave.vcd "$out"
758	        '';
759	
760	      in {
761	        devShells.default = pkgs.mkShell {
762	          packages = [
763	            mlir
764	            circt
765	            yosysPkg
766	            torchMlir
767	            llvmPackages.clang
768	            llvmPackages.llvm
769	            pythonWithTorch
770	            yosysSlang
771	            openXC7Nextpnr
772	            openXC7Prjxray
773	            openXC7Fasm
774	            prjxrayPythonDeps
775	            pkgs.cmake
776	            pkgs.ninja
777	            pkgs.gtkwave
778	            pkgs.nixfmt-classic
779	            pkgs.rr
780	          ];
781	          shellHook = ''
782	            export NEXTPNR_XILINX_DIR="${openXC7Nextpnr}/share/nextpnr"
783	            export NEXTPNR_XILINX_PYTHON_DIR="${openXC7Nextpnr}/share/nextpnr/python"
784	            export PRJXRAY_DB_DIR="${fpgaPrjxrayDb}"
785	            export PRJXRAY_PYTHON_DIR="${openXC7Prjxray}/usr/share/python3"
786	            export PYTHONPATH="${prjxrayPythonPath}''${PYTHONPATH:+:$PYTHONPATH}"
787	          '';
788	        };
789	
790	        formatter = pkgs.nixfmt-classic;
791	
792	        packages = {
793	          matmul-sv-sim = matmulSvSim;
794	          matmul-sv-wave = matmulSvWave;
795	          matmul-selftest-bitstream = matmulSelftestBitstream;
796	          tiny-stories-1m-baseline-float-selftest-all-memory-utilization =
797	            tinyStories1mBaselineFloatSelftestAllMemory.utilizationReport;
798	        };
799	
800	        apps = {
801	          docs-md = {
802	            type = "app";
803	            program = "${docsMdApp}/bin/docs-md";
804	          };
805	        };
806	
807	        checks = {
808	          nix = pkgs.runCommand "llm2fpga-nix" {
809	            nativeBuildInputs =
810	              [ pkgs.statix pkgs.deadnix pkgs.nixfmt-classic ];
811	          } ''
812	            cd ${./.}
813	            deadnix --fail .
814	            statix check .
815	            nixfmt --check .
816	            mkdir -p "$out"
817	          '';
818	
819	          python = pkgs.runCommand "llm2fpga-python" {
820	            nativeBuildInputs = [ pkgs.python311 ];
821	          } ''
822	            cd ${./.}
823	            python - <<'PY'
824	            import pathlib
825	
826	            for path in pathlib.Path(".").rglob("*.py"):
827	              if path.is_file():
828	                source = path.read_text(encoding="utf-8")
829	                compile(source, str(path), "exec")
830	            PY
831	            mkdir -p "$out"
832	          '';
833	
834	          systemverilog = pkgs.runCommand "llm2fpga-systemverilog" {
835	            nativeBuildInputs = [ pkgs.verilator ];
836	          } ''
837	            verilator \
838	              --lint-only \
839	              --timing \
840	              --language 1800-2017 \
841	              --top-module tb \
842	              --Wall \
843	              --Wno-fatal \
844	              --Wno-TIMESCALEMOD \
845	              -I${tbDataSv} \
846	              -f ${matmulSv}/sources.f \
847	              ${./sim}/tb_main.sv
848	            mkdir -p "$out"
849	          '';
850	
851	          shell = pkgs.runCommand "llm2fpga-shell" {
852	            nativeBuildInputs = [ pkgs.shellcheck pkgs.findutils ];
853	          } ''
854	            cd ${./.}
855	            if ! find . -name '*.sh' -type f | grep -q .; then
856	              mkdir -p "$out"
857	              exit 0
858	            fi
859	            find . -name '*.sh' -type f -print0 | xargs -0 shellcheck -s bash -x
860	            mkdir -p "$out"
861	          '';
862	        };
863	      });
864	}
865

file.content:
{
  description = "LLM2FPGA";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-24.05";
    nixpkgs-llvm21.url =
      "github:NixOS/nixpkgs/346dd96ad74dc4457a9db9de4f4f57dab2e5731d";
    flake-utils.url = "github:numtide/flake-utils";
    # Clone with submodules
    yosys.url = "git+https://github.com/YosysHQ/yosys?submodules=1";
    yosys-slang = {
      url = "git+https://github.com/povik/yosys-slang?submodules=1";
      flake = false;
    };
    circt-src = {
      type = "github";
      owner = "RCoeurjoly";
      repo = "circt";
      ref = "task3";
      flake = false;
    };
    circt-nix = {
      url = "git+https://github.com/dtzSiFive/circt-nix?ref=main";
      inputs."circt-src".follows = "circt-src";
      inputs."llvm-submodule-src" = {
        type = "github";
        owner = "llvm";
        repo = "llvm-project";
        rev = "972cd847efb20661ea7ee8982dd19730aa040c75";
        flake = false;
      };
    };
    nix-eda.url = "github:fossi-foundation/nix-eda";
    openXC7.url = "github:RCoeurjoly/toolchain-nix";
    nextpnrXilinxFork = {
      url =
        "git+https://github.com/RCoeurjoly/nextpnr-xilinx?ref=stable-backports&submodules=1";
      flake = false;
    };
    ypcbHack = {
      url = "github:RCoeurjoly/ypcb_00338_1p1_hack";
      flake = false;
    };
  };

  outputs = inputs@{ nixpkgs, nixpkgs-llvm21, flake-utils, yosys, circt-nix
    , nix-eda, openXC7, nextpnrXilinxFork, ypcbHack, ... }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        pkgs = import nixpkgs { inherit system; };
        pkgsLlvm21 = import nixpkgs-llvm21 { inherit system; };
        circtPkgs = circt-nix.packages.${system};
        circtBase =
          (circtPkgs.circt.override { enableSlang = false; }).overrideAttrs
          (old: { patches = old.patches or [ ]; });
        # Keep reviewer builds on a pinned upstream CIRCT plus the checked-in
        # Task 3 patch stack. Local fast iteration should use local binaries via
        # scripts/dev rather than a flake input override.
        circt = circtBase;
        yosysPkg = nix-eda.packages.${system}.yosysFull.overrideAttrs (_: {
          src = yosys.outPath;
          version = "unstable-${builtins.substring 0 8 yosys.sourceInfo.rev}";
        });
        yosysPkgWithPythonEnv = if yosysPkg ? python3-env then
          yosysPkg
        else
          (yosysPkg // { python3-env = pkgs.python311; });
        yosysSlang = pkgs.clangStdenv.mkDerivation {
          pname = "yosys-slang";
          version = "flake-input";
          src = inputs."yosys-slang";
          dylibs = [ "slang" ];
          cmakeFlags = [
            "-DYOSYS_CONFIG=${yosysPkgWithPythonEnv}/bin/yosys-config"
            "-DFMT_INSTALL:BOOL=OFF"
          ];
          nativeBuildInputs = [ pkgs.cmake pkgs.jq ];
          buildInputs = [
            yosysPkgWithPythonEnv
            yosysPkgWithPythonEnv.python3-env
            pkgs.fmt
          ];
          patchPhase = ''
            runHook prePatch
            sed -i \
              -e '/git_rev_parse(YOSYS_SLANG_REVISION/c\set(YOSYS_SLANG_REVISION flake-input)' \
              -e '/git_rev_parse(SLANG_REVISION/c\set(SLANG_REVISION flake-input-submodule)' \
              src/CMakeLists.txt
            runHook postPatch
          '';
          doCheck = true;
          cmakeBuildType = "Debug";
          installPhase = ''
            runHook preInstall
            mkdir -p $out/share/yosys/plugins
            cp ../build/slang.so $out/share/yosys/plugins/
            runHook postInstall
          '';
          meta = {
            description = "SystemVerilog frontend for Yosys";
            license = [ pkgs.lib.licenses.mit ];
            homepage = "https://github.com/povik/yosys-slang";
            platforms = pkgs.lib.platforms.all;
          };
        };
        llvmPackages = pkgsLlvm21.llvmPackages_21;
        # Keep LLVM for torch-mlir separate and pinned to torch-mlir's
        # submodule revision so source edits in torch-mlir do not rebuild LLVM.
        torchMlirLlvmPackages = (pkgsLlvm21.llvmPackages_git.override {
          llvmVersions = {
            "22.0.0-git" = {
              gitRelease = {
                rev = "3ca2a5fc0b84762f0e7d8a0e613fd69f7e344219";
                rev-version = "23.0.0-unstable-2026-01-20";
                sha256 = "sha256-jjdb2PtKnjYo9RIGJ82YtKmZinqEOlmm7R64SeJqTac=";
              };
            };
          };
        }).overrideScope (final: prev: {
          # This commit reports LLVM 23 in source headers, while the package set
          # key stays on llvmPackages_git. Skip nixpkgs' strict version triplet
          # guard for this custom pin.
          libllvm = (prev.libllvm.override {
            # Ensure llvm builds against the matching tblgen from this pinned
            # package set, not the default llvmPackages_git bootstrap set.
            buildLlvmPackages = final;
          }).overrideAttrs (old: {
            postConfigure = "";
            doCheck = false;
            cmakeFlags = (old.cmakeFlags or [ ]) ++ [
              (pkgsLlvm21.lib.cmakeBool "LLVM_BUILD_TESTS" false)
              (pkgsLlvm21.lib.cmakeBool "LLVM_INCLUDE_TESTS" false)
            ];
          });
        });
        inherit (llvmPackages) mlir;
        python = pkgsLlvm21.python311;
        pythonWithTorch = python.withPackages (ps: [ ps.torch ps.packaging ]);
        pythonWithTinyStories =
          python.withPackages (ps: [ ps.torch ps.packaging ps.transformers ]);
        nanobindBootstrap =
          pkgsLlvm21.callPackage ./nix/nanobind-bootstrap.nix {
            inherit python;
          };
        mlirForTorchMlir = (torchMlirLlvmPackages.mlir.override {
          devExtraCmakeFlags =
            [ (pkgsLlvm21.lib.cmakeBool "MLIR_ENABLE_BINDINGS_PYTHON" true) ];
        }).overrideAttrs (old: {
          doCheck = false;
          nativeBuildInputs = old.nativeBuildInputs ++ [ python ];
          preConfigure = (old.preConfigure or "") + ''
            export PYTHONPATH="${python.pkgs.pybind11}/${python.sitePackages}:${nanobindBootstrap}/${python.sitePackages}:''${PYTHONPATH:-}"
          '';
          cmakeFlags = (old.cmakeFlags or [ ]) ++ [
            (pkgsLlvm21.lib.cmakeBool "LLVM_BUILD_TESTS" false)
            (pkgsLlvm21.lib.cmakeFeature "Python3_EXECUTABLE"
              "${python}/bin/python3")
            (pkgsLlvm21.lib.cmakeFeature "Python_EXECUTABLE"
              "${python}/bin/python3")
            (pkgsLlvm21.lib.cmakeFeature "pybind11_DIR"
              "${python.pkgs.pybind11}/${python.sitePackages}/pybind11/share/cmake/pybind11")
            (pkgsLlvm21.lib.cmakeFeature "nanobind_DIR"
              "${nanobindBootstrap}/${python.sitePackages}/nanobind/cmake")
          ];
        });
        openXC7Packages = openXC7.packages.${system};
        openXC7Fasm = openXC7Packages.fasm;
        openXC7Nextpnr = openXC7Packages.nextpnr-xilinx.overrideAttrs
          (_: { src = nextpnrXilinxFork; });
        openXC7Chipdb = openXC7Packages.nextpnr-xilinx-chipdb.kintex7.override {
          chipdbFootprints = [ "xc7k480tffg1156" ];
          "nextpnr-xilinx" = openXC7Nextpnr;
        };
        openXC7Prjxray = openXC7Packages.prjxray;
        prjxrayPythonDeps = pkgs.python312.withPackages (ps: [
          ps.pyyaml
          ps.simplejson
          ps.intervaltree
          ps.pyjson5
          ps.progressbar2
        ]);
        fpgaPartFamily = "kintex7";
        fpgaPartName = "xc7k480tffg1156-1";
        fpgaPrjxrayDb = "${openXC7Nextpnr}/share/nextpnr/external/prjxray-db";
        fpgaPrjxrayFamilyDb = "${fpgaPrjxrayDb}/${fpgaPartFamily}";
        fpgaPartFile = "${fpgaPrjxrayFamilyDb}/${fpgaPartName}/part.yaml";
        fpgaChipdb = "${openXC7Chipdb}/xc7k480tffg1156.bin";
        prjxrayPythonPath =
          "${openXC7Fasm}/lib/python3.12/site-packages:${prjxrayPythonDeps}/${pkgs.python312.sitePackages}:${openXC7Prjxray}/usr/share/python3";
        torchMlir = pkgsLlvm21.callPackage ./torch-mlir.nix {
          inherit python;
          nanobind = nanobindBootstrap;
          inherit (torchMlirLlvmPackages) tblgen;
          mlir = mlirForTorchMlir;
          inherit (torchMlirLlvmPackages) llvm;
        };

        pipelineScripts = ./scripts/pipeline;
        fpPrimsSv = ./rtl/fp/circt_fp_primitives.sv;
        tinyStories1m = let
          modelId = "roneneldan/TinyStories-1M";
          revision = "77f1b168e219585646439073245fe87e56b3023e";
          fetch = file: hash:
            pkgs.fetchurl {
              url =
                "https://huggingface.co/${modelId}/resolve/${revision}/${file}";
              inherit hash;
            };
          snapshot = pkgs.linkFarm "tinystories-1m-hf-snapshot" [
            {
              name = "config.json";
              path = fetch "config.json"
                "sha256-/3TDDV67WrHaDy6kea33GXxQS0K1UiqFjDNKuR7UlYw=";
            }
            {
              name = "pytorch_model.bin";
              path = fetch "pytorch_model.bin"
                "sha256-B/lgnqiCuBY/87I9QOK4LLcV1AljG+sVyEsWTzh32uc=";
            }
          ];
        in {
          inherit snapshot;
          sourceDir = ./TinyStories;
          adapterPy = ./TinyStories/model_adapter.py;
        };

        pipelineLib = import ./nix/pipeline.nix {
          inherit pkgs mlir circt yosysPkg yosysSlang torchMlir python;
          inherit pipelineScripts;
        };

        modelRegistry = import ./nix/models.nix {
          inherit (pipelineLib) registerModel;
          inherit pythonWithTorch pythonWithTinyStories torchMlir python;
          inherit tinyStories1m;
          inherit fpPrimsSv;
          compilePyTorch = ./scripts/compile-pytorch.py;
          matmulPy = ./src/matmul.py;
          matmulAdapterPy = ./src/matmul_adapter.py;
          matmulSrcDir = ./src;
          simDir = ./sim;
        };

        matmulSv = modelRegistry.matmul.pipeline.sv;
        tinyStories1mBaselineFloatIl =
          modelRegistry."tiny-stories-1m-baseline-float".pipeline.il;
        tinyStoriesSelftestTop = ./rtl/tiny_stories_selftest_top.sv;
        # https://docs.amd.com/v/u/en-US/7-series-product-selection-guide, search XC7K480T
        fpgaCapacities = {
          slices = 74650;
          clb_luts = 298600;
          clb_ffs = 597200;
          dsp = 1920;
          bram36 = 955;
          bram_kb = 34380;
        };

        boardXdc = "${ypcbHack}/constraints/ypcb003381p1.xdc";

        mkYosysRtlil = { name, quiet ? false, memoryLimitKb ? null, script }:
          pkgs.runCommand "${name}.il" { } ''
            cat > run.ys <<EOF
            ${script}
            EOF
            ${pkgs.lib.optionalString (memoryLimitKb != null) ''
              ulimit -v ${toString memoryLimitKb}
            ''}
            ${yosysPkg}/bin/yosys ${
              pkgs.lib.optionalString quiet "-q"
            } -m ${yosysSlang}/share/yosys/plugins/slang.so -s run.ys

            if [ ! -e "$out" ]; then
              echo "mkYosysRtlil expected output path was not created: $out" >&2
              echo "--- run.ys ---" >&2
              cat run.ys >&2
              exit 1
            fi
          '';

        mkSynthStageIl = { name, stageId, stageLabel, inputIl, topName
          , topSv ? null, quiet ? false, memoryLimitKb ? null, preCommands ? [ ]
          , commands }:
          pkgs.runCommand "${name}-${stageId}.il" { } ''
            cat > run.ys <<EOF
            ${builtins.concatStringsSep "\n" ([ "read_rtlil ${inputIl}" ]
              ++ pkgs.lib.optional (topSv != null) "read_slang ${topSv}"
              ++ [ "hierarchy -top ${topName} -check" ] ++ preCommands
              ++ commands ++ [ "write_rtlil $out" ])}
            EOF

            ${pkgs.lib.optionalString (memoryLimitKb != null) ''
              ulimit -v ${toString memoryLimitKb}
            ''}

            echo "[mkSynthJson:${name}] ${stageLabel}" >&2
            ${yosysPkg}/bin/yosys ${pkgs.lib.optionalString quiet "-q"} ${
              pkgs.lib.optionalString (topSv != null)
              "-m ${yosysSlang}/share/yosys/plugins/slang.so"
            } -s run.ys

            if [ ! -e "$out" ]; then
              echo "mkSynthJson ${stageId} expected output path was not created: $out" >&2
              echo "--- run.ys ---" >&2
              cat run.ys >&2
              exit 1
            fi
          '';

        mkSynthStageMemoryMapIl = { name, stageId, stageLabel, inputIl, topName
          , quiet ? false, memoryLimitKb ? null }:
          pkgs.runCommand "${name}-${stageId}.il" { } ''
            ${pkgs.gawk}/bin/awk '
              /^module / { mod = $2 }
              /^[[:space:]]*cell \$mem/ { mods[mod] = 1 }
              END {
                for (mod in mods)
                  print mod
              }
            ' ${inputIl} | sort > stage-modules.txt

            cat > run.ys <<EOF
            read_rtlil ${inputIl}
            hierarchy -top ${topName} -check
            EOF

            while IFS= read -r moduleName; do
              printf '%s\n' \
                "cd $moduleName" \
                'memory_map' \
                'cd ..' \
                >> run.ys
            done < stage-modules.txt

            printf '%s\n' "write_rtlil $out" >> run.ys

            ${pkgs.lib.optionalString (memoryLimitKb != null) ''
              ulimit -v ${toString memoryLimitKb}
            ''}

            echo "[mkSynthJson:${name}] ${stageLabel}" >&2
            ${yosysPkg}/bin/yosys ${
              pkgs.lib.optionalString quiet "-q"
            } -s run.ys

            if [ ! -e "$out" ]; then
              echo "mkSynthJson ${stageId} expected output path was not created: $out" >&2
              echo "--- run.ys ---" >&2
              cat run.ys >&2
              exit 1
            fi
          '';

        mkSynthStageJson = { name, stageId, stageLabel, inputIl, quiet ? false
          , memoryLimitKb ? null }:
          pkgs.runCommand "${name}.json" { } ''
            ${pkgs.python311}/bin/python3 ${
              ./scripts/pipeline/filter_rtlil_modules.py
            } \
              --input ${inputIl} \
              --output stage8-stripped.il \
              --drop-escaped-uppercase-modules

            cat > run.ys <<EOF
            read_rtlil stage8-stripped.il
            proc
            write_json $out
            EOF

            ${pkgs.lib.optionalString (memoryLimitKb != null) ''
              ulimit -v ${toString memoryLimitKb}
            ''}

            echo "[mkSynthJson:${name}] ${stageLabel}" >&2
            ${yosysPkg}/bin/yosys ${
              pkgs.lib.optionalString quiet "-q"
            } -s run.ys

            if [ ! -e "$out" ]; then
              echo "mkSynthJson ${stageId} expected output path was not created: $out" >&2
              echo "--- run.ys ---" >&2
              cat run.ys >&2
              exit 1
            fi
          '';

        mkSynthJsonStages = { name, modelIl, topName, topSv ? null
          , quiet ? false, memoryLimitKb ? null }: rec {
            stage1 = mkSynthStageIl {
              inherit name topName topSv quiet memoryLimitKb;
              stageId = "stage1";
              stageLabel = "stage1 synth_xilinx begin:prepare";
              inputIl = modelIl;
              preCommands = [ "proc" ];
              commands = [
                "synth_xilinx -family xc7 -top ${topName} -noiopad -run begin:prepare"
              ];
            };

            stage2 = mkSynthStageIl {
              inherit name topName quiet memoryLimitKb;
              stageId = "stage2";
              stageLabel = "stage2 synth_xilinx coarse:map_memory";
              inputIl = stage1;
              commands = [
                "synth_xilinx -family xc7 -top ${topName} -noiopad -run coarse:map_memory"
              ];
            };

            stage3 = mkSynthStageIl {
              inherit name topName quiet memoryLimitKb;
              stageId = "stage3";
              stageLabel = "stage3 opt -fast -full";
              inputIl = stage2;
              commands = [ "opt -fast -full" ];
            };

            stage4 = mkSynthStageMemoryMapIl {
              inherit name topName quiet memoryLimitKb;
              stageId = "stage4";
              stageLabel = "stage4 targeted memory_map";
              inputIl = stage3;
            };

            stage5 = mkSynthStageIl {
              inherit name topName quiet memoryLimitKb;
              stageId = "stage5";
              stageLabel = "stage5 synth_xilinx fine:fine";
              inputIl = stage4;
              commands = [
                "synth_xilinx -family xc7 -top ${topName} -noiopad -run fine:fine"
              ];
            };

            stage6 = mkSynthStageIl {
              inherit name topName quiet memoryLimitKb;
              stageId = "stage6";
              stageLabel = "stage6 synth_xilinx map_cells:map_cells";
              inputIl = stage5;
              commands = [
                "synth_xilinx -family xc7 -top ${topName} -noiopad -run map_cells:map_cells"
              ];
            };

            stage7 = mkSynthStageIl {
              inherit name topName quiet memoryLimitKb;
              stageId = "stage7";
              stageLabel = "stage7 synth_xilinx map_ffs:map_ffs";
              inputIl = stage6;
              commands = [
                "synth_xilinx -family xc7 -top ${topName} -noiopad -run map_ffs:map_ffs"
              ];
            };

            stage8 = mkSynthStageIl {
              inherit name topName quiet memoryLimitKb;
              stageId = "stage8";
              stageLabel = "stage8 final synth/write";
              inputIl = stage7;
              commands = [
                "synth_xilinx -family xc7 -top ${topName} -noiopad -run map_luts:check"
              ];
            };

            stage9 = mkSynthStageJson {
              inherit name quiet memoryLimitKb;
              stageId = "stage9";
              stageLabel = "stage9 write_json";
              inputIl = stage8;
            };

            json = stage9;
          };

        appendYosysCommands = commands: ''
          cat >> run.ys <<EOF
          ${pkgs.lib.concatStringsSep "\n" commands}
          EOF
        '';

        appendReadSlangFromFilelist = { svFilelist, topSv }: ''
          {
            printf 'read_slang --threads 1 --no-proc'
            while IFS= read -r line; do
              if [ -z "''${line//[[:space:]]/}" ]; then
                continue
              fi
              if [ "''${line#\#}" != "$line" ]; then
                continue
              fi
              printf ' %q' "$line"
            done < ${svFilelist}
            printf ' %q' ${topSv}
            printf '\n'
          } >> run.ys
        '';

        mkSynthJson =
          { name, modelIl ? null, svFilelist ? null, topName, topSv }:
          let
            useModelIl = modelIl != null;
            useSvFilelist = svFilelist != null;
            inputScript = if useModelIl then
              appendYosysCommands
              ([ "read_rtlil ${modelIl}" ] ++ [ "read_slang ${topSv}" ])
            else
              appendReadSlangFromFilelist {
                inherit svFilelist;
                inherit topSv;
              };
          in assert pkgs.lib.assertMsg (useModelIl != useSvFilelist)
            "mkSynthJson requires exactly one of `modelIl` or `svFilelist`";
          pkgs.runCommand "${name}.json" { } ''
            ${inputScript}
            ${appendYosysCommands [
              "hierarchy -top ${topName} -check"
              "proc"
              "synth_xilinx -family xc7 -top ${topName} -noiopad -json $out"
            ]}

            echo "[mkSynthJson:${name}] stage8 final synth/write" >&2
            ${yosysPkg}/bin/yosys -m ${yosysSlang}/share/yosys/plugins/slang.so -s run.ys

            if [ ! -e "$out" ]; then
              echo "mkSynthJson expected output path was not created: $out" >&2
              echo "--- run.ys ---" >&2
              cat run.ys >&2
              exit 1
            fi
          '';

        mkMappedJsonUtilizationReport =
          { name, capacities, topName, designJson }:
          pkgs.runCommand "${name}-utilization" { } ''
            mkdir -p "$out"
            ${pkgs.python311}/bin/python3 ${
              ./scripts/pipeline/write_utilization_report.py
            } \
              --design-json ${designJson} \
              --top ${topName} \
              --summary-json "$out/summary.json" \
              --summary-txt "$out/summary.txt" \
              --stat-json "$out/stat.json" \
              --capacity-slices ${toString capacities.slices} \
              --capacity-clb-luts ${toString capacities.clb_luts} \
              --capacity-clb-ffs ${toString capacities.clb_ffs} \
              --capacity-dsp ${toString capacities.dsp} \
              --capacity-bram36 ${toString capacities.bram36} \
              --capacity-bram-kb ${toString capacities.bram_kb}
          '';

        mkExternalizedMemoryPlan =
          { name, modelIl, minModuleBits ? (128 * 1024) }:
          pkgs.runCommand "${name}-external-memory-plan" { } ''
            ${pkgs.python311}/bin/python3 ${
              ./scripts/pipeline/externalize_large_memories.py
            } \
              --input ${modelIl} \
              --output-script externalize.ys \
              --output-report report.json \
              --min-module-bits ${toString minModuleBits}
            mkdir -p "$out"
            cp externalize.ys "$out/externalize.ys"
            cp report.json "$out/report.json"
          '';

        mkTinyStoriesSelftestBundle = { name, topName, modelIl, capacities
          , externalMemoryMinModuleBits ? (128 * 1024) }:
          let
            top = tinyStoriesSelftestTop;
            modelOptIl = mkYosysRtlil {
              name = "${name}-model-opt";
              script = ''
                read_rtlil ${modelIl}
                hierarchy -top main -check
                proc
                opt_expr
                opt_clean
                clean
                write_rtlil $out
              '';
            };
            externalMemoryPlan = mkExternalizedMemoryPlan {
              inherit name;
              modelIl = modelOptIl;
              minModuleBits = externalMemoryMinModuleBits;
            };
            modelShellIl = mkYosysRtlil {
              name = "${name}-model-shell";
              script = ''
                read_rtlil ${modelOptIl}
                script ${externalMemoryPlan}/externalize.ys
                hierarchy -top main -check
                write_rtlil $out
              '';
            };
            stages = mkSynthJsonStages {
              inherit name topName;
              modelIl = modelShellIl;
              topSv = top;
              quiet = true;
            };
            utilizationReport = mkMappedJsonUtilizationReport {
              inherit name capacities topName;
              designJson = stages.json;
            };
          in { inherit stages utilizationReport; };

        docsMdApp = pkgs.writeShellApplication {
          name = "docs-md";
          runtimeInputs = [ pkgs.pandoc pkgs.coreutils ];
          text = ''
          set -euo pipefail

          repo="$(pwd -P)"
          if [ "$#" -gt 0 ]; then
            repo="$1"
          fi
          repo="$(cd "$repo" && pwd -P)"

          while IFS= read -r src; do
            [ -f "$src" ] || continue
            dst="''${src%.org}.md"
            pandoc "$src" -f org -t gfm -o "$dst"
          done < <(printf '%s\n' "$repo/README.org" "$repo"/deliverables/*.org "$repo"/docs/*.org)
          echo "Generated markdown docs in: $repo"
          '';
        };

        mkXdc = { name, includeBoardXdc ? true, extraConstraints ? [ ] }:
          let
            constraintFiles = (if includeBoardXdc then [ boardXdc ] else [ ])
              ++ extraConstraints;
          in pkgs.runCommand "${name}.xdc" { inherit constraintFiles; } ''
            cat $constraintFiles > "$out"
          '';

        mkFasm = { name, xdc, json }:
          pkgs.runCommand "${name}.fasm" { } ''
            if [ ! -f "${fpgaChipdb}" ]; then
              echo "chipdb file missing: ${fpgaChipdb}" >&2
              exit 1
            fi

            ${openXC7Nextpnr}/bin/nextpnr-xilinx \
              --chipdb "${fpgaChipdb}" \
              --xdc ${xdc} \
              --json ${json} \
              --fasm "$out"
          '';

        mkBitstream = { name, fasm, framesBase }:
          pkgs.runCommand "${name}.bit" {
            nativeBuildInputs =
              [ openXC7Fasm openXC7Prjxray prjxrayPythonDeps ];
          } ''
            set -euo pipefail
            export PYTHONPATH="${prjxrayPythonPath}''${PYTHONPATH:+:$PYTHONPATH}"
            export PRJXRAY_PYTHON_DIR="${openXC7Prjxray}/usr/share/python3"
            export PRJXRAY_DB_DIR="${fpgaPrjxrayFamilyDb}"
            tmpdir="$(mktemp -d)"
            frames="$tmpdir/${framesBase}.frm"
            fasm2frames \
              --db-root "${fpgaPrjxrayFamilyDb}" \
              --part ${fpgaPartName} \
              ${fasm} "$frames"
            xc7frames2bit \
              --part_file "${fpgaPartFile}" \
              --frm_file "$frames" \
              --output_file "$out"
          '';

        tinyStories1mBaselineFloatSelftestAllMemory =
          mkTinyStoriesSelftestBundle {
            name = "tiny-stories-1m-baseline-float-selftest-all-memory";
            topName = "tiny_stories_selftest_top";
            modelIl = tinyStories1mBaselineFloatIl;
            capacities = fpgaCapacities;
          };

        matmulSelftestTop = ./fpga/rtl/matmul_selftest_top.sv;
        matmulSelftestJson = mkSynthJson {
          name = "matmul-selftest";
          svFilelist = "${matmulSv}/sources.f";
          topName = "matmul_selftest_top";
          topSv = matmulSelftestTop;
        };
        matmulSelftestXdc = mkXdc {
          name = "matmul-selftest";
          includeBoardXdc = false;
          extraConstraints = [ ./fpga/constraints/matmul_selftest.xdc ];
        };
        matmulSelftestFasm = mkFasm {
          name = "matmul-selftest";
          xdc = matmulSelftestXdc;
          json = matmulSelftestJson;
        };
        matmulSelftestBitstream = mkBitstream {
          name = "matmul-selftest";
          fasm = matmulSelftestFasm;
          framesBase = "matmul-selftest";
        };

        tbDataSv = pkgs.runCommand "tb-data-sv" { } ''
          mkdir -p "$out"
          MATMUL_PY=${./src/matmul.py} \
          ${pythonWithTorch}/bin/python ${
            ./sim
          }/gen_tb_data.py > "$out/tb_data.sv"
        '';

        simMain = pkgs.runCommand "sim-main" {
          buildInputs = [ pkgs.verilator pkgs.gcc pkgs.gnumake ];
        } ''
          set -euo pipefail
          mkdir -p "$out/obj_dir"
          verilator --binary --timing --language 1800-2017 -Wno-fatal \
            -I${tbDataSv} \
            -top tb -Mdir "$out/obj_dir" -o sim_main \
            -f ${matmulSv}/sources.f ${./sim/tb_main.sv}
        '';

        matmulSvSim = pkgs.runCommand "matmul-sv-sim.json" {
          buildInputs = [ pkgs.gawk pkgs.gnugrep ];
        } ''
                    set -euo pipefail
                    ${simMain}/obj_dir/sim_main 2>&1 | tee sim.log
                    pass_line="$(${pkgs.gnugrep}/bin/grep -Eo 'PASS: expected [0-9]+ got [0-9]+' sim.log | tail -n1 || true)"
                    if [ -z "$pass_line" ]; then
                      echo "SV simulation did not produce a PASS line" >&2
                      exit 1
                    fi
                    expected="$(${pkgs.gawk}/bin/awk '{print $3}' <<<"$pass_line")"
                    got="$(${pkgs.gawk}/bin/awk '{print $5}' <<<"$pass_line")"
                    cat > "$out" <<EOF
          {
            "status": "PASS",
            "expected": $expected,
            "got": $got
          }
          EOF
        '';

        matmulSvWave = pkgs.runCommand "matmul-wave.vcd" {
          buildInputs = [ pkgs.verilator pkgs.gcc pkgs.gnumake ];
        } ''
          set -euo pipefail
          mkdir -p obj_dir
          verilator --binary --trace -DENABLE_WAVES -DENABLE_WAVES_VCD --timing --language 1800-2017 -Wno-fatal \
            -I${tbDataSv} \
            -top tb -Mdir obj_dir -o sim_main \
            -f ${matmulSv}/sources.f ${./sim/tb_main.sv}
          ./obj_dir/sim_main
          if [ ! -f wave.vcd ]; then
            echo "wave.vcd was not produced by simulation" >&2
            exit 1
          fi
          cp wave.vcd "$out"
        '';

      in {
        devShells.default = pkgs.mkShell {
          packages = [
            mlir
            circt
            yosysPkg
            torchMlir
            llvmPackages.clang
            llvmPackages.llvm
            pythonWithTorch
            yosysSlang
            openXC7Nextpnr
            openXC7Prjxray
            openXC7Fasm
            prjxrayPythonDeps
            pkgs.cmake
            pkgs.ninja
            pkgs.gtkwave
            pkgs.nixfmt-classic
            pkgs.rr
          ];
          shellHook = ''
            export NEXTPNR_XILINX_DIR="${openXC7Nextpnr}/share/nextpnr"
            export NEXTPNR_XILINX_PYTHON_DIR="${openXC7Nextpnr}/share/nextpnr/python"
            export PRJXRAY_DB_DIR="${fpgaPrjxrayDb}"
            export PRJXRAY_PYTHON_DIR="${openXC7Prjxray}/usr/share/python3"
            export PYTHONPATH="${prjxrayPythonPath}''${PYTHONPATH:+:$PYTHONPATH}"
          '';
        };

        formatter = pkgs.nixfmt-classic;

        packages = {
          matmul-sv-sim = matmulSvSim;
          matmul-sv-wave = matmulSvWave;
          matmul-selftest-bitstream = matmulSelftestBitstream;
          tiny-stories-1m-baseline-float-selftest-all-memory-utilization =
            tinyStories1mBaselineFloatSelftestAllMemory.utilizationReport;
        };

        apps = {
          docs-md = {
            type = "app";
            program = "${docsMdApp}/bin/docs-md";
          };
        };

        checks = {
          nix = pkgs.runCommand "llm2fpga-nix" {
            nativeBuildInputs =
              [ pkgs.statix pkgs.deadnix pkgs.nixfmt-classic ];
          } ''
            cd ${./.}
            deadnix --fail .
            statix check .
            nixfmt --check .
            mkdir -p "$out"
          '';

          python = pkgs.runCommand "llm2fpga-python" {
            nativeBuildInputs = [ pkgs.python311 ];
          } ''
            cd ${./.}
            python - <<'PY'
            import pathlib

            for path in pathlib.Path(".").rglob("*.py"):
              if path.is_file():
                source = path.read_text(encoding="utf-8")
                compile(source, str(path), "exec")
            PY
            mkdir -p "$out"
          '';

          systemverilog = pkgs.runCommand "llm2fpga-systemverilog" {
            nativeBuildInputs = [ pkgs.verilator ];
          } ''
            verilator \
              --lint-only \
              --timing \
              --language 1800-2017 \
              --top-module tb \
              --Wall \
              --Wno-fatal \
              --Wno-TIMESCALEMOD \
              -I${tbDataSv} \
              -f ${matmulSv}/sources.f \
              ${./sim}/tb_main.sv
            mkdir -p "$out"
          '';

          shell = pkgs.runCommand "llm2fpga-shell" {
            nativeBuildInputs = [ pkgs.shellcheck pkgs.findutils ];
          } ''
            cd ${./.}
            if ! find . -name '*.sh' -type f | grep -q .; then
              mkdir -p "$out"
              exit 0
            fi
            find . -name '*.sh' -type f -print0 | xargs -0 shellcheck -s bash -x
            mkdir -p "$out"
          '';
        };
      });
}

#!/usr/bin/env python3
"""Estimate FPGA resource usage from a mapped Yosys JSON design."""

from __future__ import annotations

import argparse
from collections import Counter
import json
import math
from pathlib import Path
import re
from typing import Any


LUT_RE = re.compile(r"^(LUT[1-6]|LUT6_2|CFGLUT5)$")
FF_TYPES = {"FDCE", "FDPE", "FDRE", "FDSE", "LDCE", "LDPE"}
DSP_TYPES = {"DSP48E1"}
BRAM36_TYPES = {"FIFO36E1", "RAMB36E1"}
BRAM18_TYPES = {"FIFO18E1", "RAMB18E1"}

SUMMARY_ORDER = ["slices_lower_bound", "clb_luts", "clb_ffs", "dsp", "bram36", "bram36_equiv", "bram_kb"]
CAPACITY = {
    "slices_lower_bound": "capacity_slices",
    "clb_luts": "capacity_clb_luts",
    "clb_ffs": "capacity_clb_ffs",
    "dsp": "capacity_dsp",
    "bram36": "capacity_bram36",
    "bram36_equiv": "capacity_bram36",
    "bram_kb": "capacity_bram_kb",
}


def parse_args() -> argparse.Namespace:
    p = argparse.ArgumentParser()
    for name in ["design-json", "top", "summary-json", "summary-txt", "stat-json"]:
        p.add_argument(f"--{name}", required=True)
    for name in ["slices", "clb-luts", "clb-ffs", "dsp", "bram36", "bram-kb"]:
        p.add_argument(f"--capacity-{name}", type=int, required=True)
    return p.parse_args()


def write_json(path: str, payload: dict[str, Any]) -> None:
    Path(path).write_text(json.dumps(payload, indent=2, sort_keys=True) + "\n", encoding="utf-8")


def cell_counts(module: dict[str, Any]) -> Counter[str]:
    counts: Counter[str] = Counter()
    for cell in (module.get("cells") or {}).values():
        if isinstance(cell.get("type"), str):
            counts[cell["type"]] += 1
    return counts


def leaf_counts(
    modules: dict[str, dict[str, Any]],
    name: str,
    memo: dict[str, Counter[str]],
    stack: set[str],
) -> Counter[str]:
    if name in memo:
        return memo[name]
    if name in stack:
        raise SystemExit(f"module hierarchy cycle at {name}")
    if name not in modules:
        raise SystemExit(f"module {name!r} not found in design JSON")

    stack.add(name)
    counts: Counter[str] = Counter()
    for cell_type, instances in cell_counts(modules[name]).items():
        if cell_type not in modules:
            counts[cell_type] += instances
            continue
        for leaf_type, leaves_per_instance in leaf_counts(modules, cell_type, memo, stack).items():
            counts[leaf_type] += instances * leaves_per_instance
    stack.remove(name)

    memo[name] = counts
    return counts


def as_dict(counts: Counter[str]) -> dict[str, int]:
    return dict(sorted(counts.items()))


def summarize(counts: Counter[str], args: argparse.Namespace) -> dict[str, Any]:
    def count(types: set[str]) -> int:
        return sum(n for cell_type, n in counts.items() if cell_type in types)

    def row(key: str, used: float) -> dict[str, float | int]:
        capacity = getattr(args, CAPACITY[key])
        return {
            "used": used,
            "capacity": capacity,
            "pct": 0.0 if capacity <= 0 else round(100.0 * used / capacity, 2),
        }

    luts = sum(n for cell_type, n in counts.items() if LUT_RE.match(cell_type))
    ffs = count(FF_TYPES)
    bram36 = count(BRAM36_TYPES)
    bram18 = count(BRAM18_TYPES)
    used = {
        "slices_lower_bound": max(math.ceil(luts / 8), math.ceil(ffs / 8)),
        "clb_luts": luts,
        "clb_ffs": ffs,
        "dsp": count(DSP_TYPES),
        "bram36": bram36,
        "bram18": bram18,
        "bram36_equiv": bram36 + bram18 / 2.0,
        "bram_kb": bram36 * 36 + bram18 * 18,
    }
    resources = {"bram18": {"used": bram18}}
    for key in SUMMARY_ORDER:
        resources[key] = row(key, used[key])
    return resources


def top_types(counts: Counter[str]) -> list[dict[str, int]]:
    return [{"type": cell_type, "count": count} for cell_type, count in counts.most_common(12)]


def number(value: float | int) -> str:
    return f"{value:g}" if isinstance(value, float) else str(value)


def summary_text(top: str, resources: dict[str, Any], top_cell_types: list[dict[str, int]]) -> str:
    lines = [f"top: {top}", "estimated mapped resource usage:"]
    for key in SUMMARY_ORDER:
        row = resources[key]
        lines.append(f"- {key}: {number(row['used'])} / {row['capacity']} ({row['pct']:.2f}%)")
    if resources["bram18"]["used"]:
        lines.append(f"- bram18: {resources['bram18']['used']}")
    if top_cell_types:
        lines.append("largest leaf cell types:")
        lines += [f"- {row['type']}: {row['count']}" for row in top_cell_types]
    return "\n".join(lines) + "\n"


def main() -> None:
    args = parse_args()
    design = json.loads(Path(args.design_json).read_text(encoding="utf-8"))
    modules = design.get("modules")
    if not isinstance(modules, dict):
        raise SystemExit(f"{args.design_json} does not contain a modules object")

    memo: dict[str, Counter[str]] = {}
    top_counts = leaf_counts(modules, args.top, memo, set())
    resources = summarize(top_counts, args)
    top_cell_types = top_types(top_counts)

    write_json(args.summary_json, {
        "design_json": args.design_json,
        "top": args.top,
        "resources": resources,
        "top_leaf_cell_types": top_cell_types,
    })
    Path(args.summary_txt).write_text(summary_text(args.top, resources, top_cell_types), encoding="utf-8")
    write_json(args.stat_json, {
        "design_json": args.design_json,
        "top": args.top,
        "top_leaf_cell_counts": as_dict(top_counts),
        "modules": {
            name: {
                "direct_cell_counts": as_dict(cell_counts(module)),
                "leaf_cell_counts": as_dict(leaf_counts(modules, name, memo, set())),
            }
            for name, module in sorted(modules.items())
        },
    })


if __name__ == "__main__":
    main()
